use std::fs;
use std::path::Path;

use symphony::error::SymphonyError;
use symphony::ssh::{parse_target, remote_shell_command, run, ssh_args, SshTarget};

fn write_fake_ssh(dir: &Path, script: &str) {
    let ssh = dir.join("ssh");
    fs::write(&ssh, script).unwrap();
    #[cfg(unix)]
    {
        use std::os::unix::fs::PermissionsExt;
        fs::set_permissions(&ssh, fs::Permissions::from_mode(0o755)).unwrap();
    }
}

#[test]
fn parse_target_supports_host_port_user_prefix_and_ipv6_rules() {
    assert_eq!(
        parse_target("localhost:2222"),
        SshTarget {
            destination: "localhost".to_string(),
            port: Some("2222".to_string())
        }
    );

    assert_eq!(
        parse_target("root@127.0.0.1:2200"),
        SshTarget {
            destination: "root@127.0.0.1".to_string(),
            port: Some("2200".to_string())
        }
    );

    assert_eq!(
        parse_target("root@[::1]:2200"),
        SshTarget {
            destination: "root@[::1]".to_string(),
            port: Some("2200".to_string())
        }
    );

    assert_eq!(
        parse_target("::1:2200"),
        SshTarget {
            destination: "::1:2200".to_string(),
            port: None
        }
    );
}

#[test]
fn ssh_args_respect_symphony_ssh_config_and_ttyless_shape() {
    let previous = std::env::var("SYMPHONY_SSH_CONFIG").ok();
    std::env::set_var("SYMPHONY_SSH_CONFIG", "/tmp/symphony-test-ssh-config");

    let args = ssh_args("worker-01:2200", "echo ready");

    match previous {
        Some(value) => std::env::set_var("SYMPHONY_SSH_CONFIG", value),
        None => std::env::remove_var("SYMPHONY_SSH_CONFIG"),
    }

    assert_eq!(
        args,
        vec![
            "-F",
            "/tmp/symphony-test-ssh-config",
            "-T",
            "-p",
            "2200",
            "worker-01",
            "bash -lc 'echo ready'",
        ]
    );
}

#[test]
fn remote_shell_command_escapes_embedded_single_quotes() {
    assert_eq!(
        remote_shell_command("printf 'hello'"),
        r#"bash -lc 'printf '"'"'hello'"'"''"#
    );
}

#[test]
fn run_returns_ssh_not_found_when_ssh_is_unavailable() {
    let tmp = tempfile::tempdir().unwrap();
    let previous_path = std::env::var("PATH").ok();
    std::env::set_var("PATH", tmp.path());

    let result = run("localhost", "printf ok");

    match previous_path {
        Some(value) => std::env::set_var("PATH", value),
        None => std::env::remove_var("PATH"),
    }

    assert!(matches!(result, Err(SymphonyError::SshNotFound)));
}

#[test]
fn run_executes_fake_ssh_with_expected_arguments() {
    let tmp = tempfile::tempdir().unwrap();
    let trace = tmp.path().join("ssh.trace");
    let previous_path = std::env::var("PATH").ok();

    write_fake_ssh(
        tmp.path(),
        &format!(
            "#!/bin/sh\nprintf 'ARGV:%s\\n' \"$*\" >> '{}'\nexit 0\n",
            trace.display()
        ),
    );
    std::env::set_var("PATH", tmp.path());

    let result = run("root@127.0.0.1:2200", "printf ok").unwrap();

    match previous_path {
        Some(value) => std::env::set_var("PATH", value),
        None => std::env::remove_var("PATH"),
    }

    assert_eq!(result.1, 0);
    let logged = fs::read_to_string(trace).unwrap();
    assert!(logged.contains("-T -p 2200 root@127.0.0.1 bash -lc 'printf ok'"));
}

use std::fs;
use std::path::Path;

use symphony::domain::{HooksConfig, WorkspaceConfig};
use symphony::workspace::{
    ensure_workspace_for_worker, remove_workspace_for_worker, run_before_run_hook_for_worker,
};

fn workspace_config(root: &Path) -> WorkspaceConfig {
    WorkspaceConfig {
        root: root.to_string_lossy().to_string(),
    }
}

fn write_fake_ssh(dir: &Path, trace: &Path) {
    let ssh = dir.join("ssh");
    fs::write(
        &ssh,
        format!(
            "#!/bin/sh\nprintf 'ARGV:%s\\n' \"$*\" >> '{}'\nexit 0\n",
            trace.display()
        ),
    )
    .unwrap();
    #[cfg(unix)]
    {
        use std::os::unix::fs::PermissionsExt;
        fs::set_permissions(&ssh, fs::Permissions::from_mode(0o755)).unwrap();
    }
}

#[test]
fn remote_workspace_prepare_and_hooks_should_run_over_ssh_and_keep_remote_path_identity() {
    let tmp = tempfile::tempdir().unwrap();
    let fake_bin = tempfile::tempdir().unwrap();
    let trace = tmp.path().join("ssh.trace");
    let previous_path = std::env::var("PATH").ok();
    write_fake_ssh(fake_bin.path(), &trace);
    let merged_path = match &previous_path {
        Some(value) => format!("{}:{}", fake_bin.path().display(), value),
        None => fake_bin.path().display().to_string(),
    };
    std::env::set_var("PATH", merged_path);

    let root = tmp.path().join("workspaces");
    fs::create_dir_all(&root).unwrap();
    let config = workspace_config(&root);
    let hooks = HooksConfig {
        after_create: Some("printf after-create".to_string()),
        before_run: Some("printf before-run".to_string()),
        after_run: None,
        before_remove: Some("printf before-remove".to_string()),
        timeout_ms: 5_000,
    };

    let workspace = ensure_workspace_for_worker("MT-REMOTE", &config, &hooks, Some("worker-01:2200"))
        .expect("remote workspace prepare should compile");

    run_before_run_hook_for_worker(
        Path::new(&workspace.path),
        &hooks,
        Some("worker-01:2200"),
    )
    .expect("before_run should compile");

    remove_workspace_for_worker(
        Path::new(&workspace.path),
        &config,
        &hooks,
        Some("worker-01:2200"),
    )
    .expect("remove should compile");

    match previous_path {
        Some(value) => std::env::set_var("PATH", value),
        None => std::env::remove_var("PATH"),
    }

    let remote_workspace = symphony::path_safety::canonicalize(Path::new(&config.root))
        .unwrap()
        .join("MT-REMOTE");
    assert_eq!(
        workspace.path,
        remote_workspace.to_string_lossy(),
        "remote workspace identity should stay rooted in the remote workspace path"
    );

    let logged = fs::read_to_string(&trace).unwrap_or_default();
    assert!(
        logged.contains("worker-01") && logged.contains("after-create") && logged.contains("before-run") && logged.contains("before-remove"),
        "remote workspace lifecycle should be driven by ssh command execution, got trace: {logged:?}"
    );
}

