pub async fn stop_session(mut handle: SessionHandle) -> Result<()> {
    // Drop stdin to signal EOF
    drop(handle.stdin);
    // Kill in case the process ignores the EOF
    let _ = handle.child.kill().await;
    let _ = handle.child.wait().await;
    Ok(())
}

