pub fn build_remote_launch_command(workspace_path: &str, codex_command: &[String]) -> String {
    let escaped_workspace = shell_escape(workspace_path);
    let command = codex_command
        .iter()
        .map(|part| shell_escape_if_needed(part))
        .collect::<Vec<_>>()
        .join(" ");

    format!("cd {escaped_workspace} && exec {command}")
}

fn shell_escape_if_needed(value: &str) -> String {
    if value
        .chars()
        .all(|ch| ch.is_ascii_alphanumeric() || matches!(ch, '_' | '-' | '.' | '/' | ':'))
    {
        value.to_string()
    } else {
        shell_escape(value)
