pub fn ensure_workspace_for_worker(
    identifier: &str,
    config: &WorkspaceConfig,
    hooks: &HooksConfig,
    worker_host: Option<&str>,
) -> Result<Workspace> {
    let Some(worker_host) = worker_host else {
        return ensure_workspace(identifier, config, hooks);
    };

    let safe_id = path_safety::sanitize_identifier(identifier);
    let root_path = Path::new(&config.root);
    let canonical_root = path_safety::canonicalize(root_path)?;
    let workspace_path = canonical_root.join(&safe_id);
    let workspace_string = workspace_path.to_string_lossy().to_string();

    validate_remote_workspace_path(&workspace_string)?;
    prepare_remote_workspace(worker_host, &workspace_string)?;

    if let Some(ref command) = hooks.after_create {
        run_remote_hook("after_create", command, &workspace_string, worker_host, hooks.timeout_ms)?;
    }

    Ok(Workspace {
        path: workspace_string,
        workspace_key: safe_id,
        created_now: true,
    })
}

pub fn run_before_run_hook_for_worker(
    workspace: &Path,
    hooks: &HooksConfig,
    worker_host: Option<&str>,
) -> Result<()> {
    let Some(worker_host) = worker_host else {
        return run_before_run_hook(workspace, hooks);
    };

    if let Some(ref command) = hooks.before_run {
        run_remote_hook(
            "before_run",
            command,
            &workspace.to_string_lossy(),
            worker_host,
            hooks.timeout_ms,
        )
    } else {
        Ok(())
    }
}

