pub fn remove_workspace_for_worker(
    workspace: &Path,
    config: &WorkspaceConfig,
    hooks: &HooksConfig,
    worker_host: Option<&str>,
) -> Result<()> {
    let Some(worker_host) = worker_host else {
        return remove_workspace(workspace, config, hooks);
    };

    let workspace_string = workspace.to_string_lossy().to_string();
    validate_remote_workspace_path(&workspace_string)?;

    if let Some(ref command) = hooks.before_remove {
        let before_remove_command = format!(
            "if [ -d {} ]; then cd {} && {}; fi",
            shell_escape(&workspace_string),
            shell_escape(&workspace_string),
            command
        );
        if let Err(err) = run_remote_command(worker_host, &before_remove_command, hooks.timeout_ms) {
            tracing::warn!(error = %err, "before_remove hook failure ignored");
        }
    }

    let remove_command = format!("rm -rf {}", shell_escape(&workspace_string));
    run_remote_command(worker_host, &remove_command, hooks.timeout_ms)?;
    Ok(())
}

fn validate_remote_workspace_path(workspace: &str) -> Result<()> {
    if workspace.trim().is_empty() {
        return Err(SymphonyError::InvalidWorkspaceCwd(
            "remote workspace path must not be empty".to_string(),
        ));
    }

    if workspace.contains(['\n', '\r', '\0']) {
        return Err(SymphonyError::InvalidWorkspaceCwd(
            "remote workspace path contains invalid characters".to_string(),
        ));
    }

    Ok(())
}

fn prepare_remote_workspace(worker_host: &str, workspace: &str) -> Result<()> {
    let command = format!(
        "if [ -d {path} ]; then :; elif [ -e {path} ]; then rm -rf {path} && mkdir -p {path}; else mkdir -p {path}; fi && cd {path} && pwd -P",
        path = shell_escape(workspace)
    );
    run_remote_command(worker_host, &command, 0)
}

fn run_remote_hook(
    hook_name: &str,
    command: &str,
    workspace: &str,
    worker_host: &str,
    timeout_ms: u64,
) -> Result<()> {
    let remote_command = format!("cd {} && {}", shell_escape(workspace), command);
    match run_remote_command(worker_host, &remote_command, timeout_ms) {
        Ok(()) => Ok(()),
        Err(SymphonyError::WorkspaceHookTimeout { .. }) => Err(SymphonyError::WorkspaceHookTimeout {
            hook: hook_name.to_string(),
            timeout_ms,
        }),
        Err(SymphonyError::WorkspaceHookFailed { status, .. }) => Err(SymphonyError::WorkspaceHookFailed {
            hook: hook_name.to_string(),
            status,
        }),
        Err(err) => Err(err),
    }
}

fn run_remote_command(worker_host: &str, command: &str, timeout_ms: u64) -> Result<()> {
    let (output, status) = ssh::run(worker_host, command)?;
    if status == 0 {
        Ok(())
    } else {
        let effective_timeout = if timeout_ms == 0 { 1 } else { timeout_ms };
        Err(SymphonyError::WorkspaceHookFailed {
            hook: format!("remote_command output={}", truncate_output(&output, 256)),
            status,
        })
        .map_err(|err| match err {
            SymphonyError::WorkspaceHookFailed { .. } => err,
            _ => SymphonyError::WorkspaceHookTimeout {
                hook: "remote_command".to_string(),
                timeout_ms: effective_timeout,
            },
        })
    }
}

