        created_now: true,
    })
}

pub fn run_before_run_hook_for_worker(
    workspace: &Path,
    hooks: &HooksConfig,
    worker_host: Option<&str>,
) -> Result<()> {
    let Some(worker_host) = worker_host else {
        return run_before_run_hook(workspace, hooks);
    };

    if let Some(ref command) = hooks.before_run {
        run_remote_hook(
            "before_run",
            command,
            &workspace.to_string_lossy(),
            worker_host,
            hooks.timeout_ms,
        )
    } else {
        Ok(())
    }
}

/// Run the `after_run` hook — failure is logged and ignored.
pub fn run_after_run_hook(workspace: &Path, hooks: &HooksConfig) -> Result<()> {
    if let Some(ref command) = hooks.after_run {
        match run_hook("after_run", command, workspace, hooks.timeout_ms) {
            Ok(()) => Ok(()),
            Err(e) => {
                tracing::warn!(error = %e, "after_run hook failure ignored");
                Ok(())
            }
        }
    } else {
        Ok(())
    }
}

/// Remove a workspace directory. Runs `before_remove` hook (failure ignored).
pub fn remove_workspace(
    workspace: &Path,
    config: &WorkspaceConfig,
    hooks: &HooksConfig,
) -> Result<()> {
    let canonical_root = path_safety::canonicalize(Path::new(&config.root))?;

    if workspace.exists() {
        validate_workspace_path(workspace, &canonical_root)?;

        // Run before_remove hook (failure ignored)
        if let Some(ref command) = hooks.before_remove {
            if workspace.is_dir() {
                match run_hook("before_remove", command, workspace, hooks.timeout_ms) {
                    Ok(()) => {}
                    Err(e) => {
                        tracing::warn!(error = %e, "before_remove hook failure ignored");
                    }
                }
            }
        }

        std::fs::remove_dir_all(workspace)?;
    }

    Ok(())
}

pub fn remove_workspace_for_worker(
    workspace: &Path,
    config: &WorkspaceConfig,
    hooks: &HooksConfig,
    worker_host: Option<&str>,
) -> Result<()> {
    let Some(worker_host) = worker_host else {
        return remove_workspace(workspace, config, hooks);
    };

    let workspace_string = workspace.to_string_lossy().to_string();
    validate_remote_workspace_path(&workspace_string)?;

    if let Some(ref command) = hooks.before_remove {
        let before_remove_command = format!(
            "if [ -d {} ]; then cd {} && {}; fi",
            shell_escape(&workspace_string),
            shell_escape(&workspace_string),
            command
        );
        if let Err(err) = run_remote_command(worker_host, &before_remove_command, hooks.timeout_ms) {
            tracing::warn!(error = %err, "before_remove hook failure ignored");
        }
    }

    let remove_command = format!("rm -rf {}", shell_escape(&workspace_string));
    run_remote_command(worker_host, &remove_command, hooks.timeout_ms)?;
    Ok(())
}

fn validate_remote_workspace_path(workspace: &str) -> Result<()> {
    if workspace.trim().is_empty() {
        return Err(SymphonyError::InvalidWorkspaceCwd(
            "remote workspace path must not be empty".to_string(),
        ));
    }

    if workspace.contains(['\n', '\r', '\0']) {
        return Err(SymphonyError::InvalidWorkspaceCwd(
            "remote workspace path contains invalid characters".to_string(),
        ));
    }

    Ok(())
}

