fn run_remote_hook(
    hook_name: &str,
    command: &str,
    workspace: &str,
    worker_host: &str,
    timeout_ms: u64,
) -> Result<()> {
    let remote_command = format!("cd {} && {}", shell_escape(workspace), command);
    match run_remote_command(worker_host, &remote_command, timeout_ms) {
        Ok(()) => Ok(()),
        Err(SymphonyError::WorkspaceHookTimeout { .. }) => Err(SymphonyError::WorkspaceHookTimeout {
            hook: hook_name.to_string(),
            timeout_ms,
        }),
        Err(SymphonyError::WorkspaceHookFailed { status, .. }) => Err(SymphonyError::WorkspaceHookFailed {
            hook: hook_name.to_string(),
            status,
        }),
        Err(err) => Err(err),
    }
}

fn run_remote_command(worker_host: &str, command: &str, timeout_ms: u64) -> Result<()> {
    let (output, status) = ssh::run(worker_host, command)?;
    if status == 0 {
        Ok(())
    } else {
        let effective_timeout = if timeout_ms == 0 { 1 } else { timeout_ms };
        Err(SymphonyError::WorkspaceHookFailed {
            hook: format!("remote_command output={}", truncate_output(&output, 256)),
            status,
        })
        .map_err(|err| match err {
            SymphonyError::WorkspaceHookFailed { .. } => err,
            _ => SymphonyError::WorkspaceHookTimeout {
                hook: "remote_command".to_string(),
                timeout_ms: effective_timeout,
            },
        })
    }
}

fn shell_escape(value: &str) -> String {
    format!("'{}'", value.replace('\'', "'\"'\"'"))
}

/// Truncate output to max_bytes, appending "... (truncated)" if necessary.
fn truncate_output(output: &str, max_bytes: usize) -> String {
    if output.len() <= max_bytes {
        output.to_string()
    } else {
        // Find a safe UTF-8 boundary
        let truncated = &output[..output.floor_char_boundary(max_bytes)];
        format!("{}... (truncated)", truncated)
    }
}

