            None => {
                tracing::debug!(
                    event = "retry_no_worker_capacity",
                    issue_id = %issue.id,
                    issue_identifier = %issue.identifier,
                    preferred_worker_host = retry.worker_host.as_deref().unwrap_or(""),
                    "retry issue blocked by ssh worker host pool"
                );
                self.schedule_retry_with_context(
                    &issue.id,
                    &issue.identifier,
                    retry.attempt.saturating_add(1),
                    RetryKind::Failure,
                    now_ms,
                    Some("no available ssh worker slots".to_string()),
                    retry_context,
                );
                continue;
            }
        }
    };

    self.dispatch_issue(
        &issue,
        Some(retry.attempt),
        retry.workspace_path.clone(),
        worker_host,
    );
    continue;
}

